pragma solidity ^0.8.28;

// Libraries
import {PMath} from "../../../lib/math/PMath.sol";
import {Err} from "../../../lib/Errors.sol";
import {Trade, TradeLib} from "../../../types/Trade.sol";
import {MarginViewUtils} from "./MarginViewUtils.sol";

abstract contract LiquidationViewUtils is MarginViewUtils {
    using PMath for int256;
    using PMath for uint256;

    function _calcLiqTradeAft(
        MarketMem memory market,
        UserMem memory vio,
        int256 sizeToLiq,
        int256 healthRatio
    ) internal view returns (Trade /*liqTrade*/, uint64 /*liqFeeRate*/) {
        require(0 <= healthRatio && healthRatio < PMath.IONE && sizeToLiq != 0, Err.MarketInvalidLiquidation());

        (uint256 incentiveFactor, uint64 liqFeeRate) = _getLiqSettings(healthRatio);

        uint64 kMM = _kMM(vio.addr);
        uint256 deltaMM = _calcMM(market, vio.signedSize, kMM) - _calcMM(market, vio.signedSize - sizeToLiq, kMM);

        uint256 incentive = deltaMM.mulDown(incentiveFactor);
        uint256 annualizedIncentive = (incentive * 365 days) / market.timeToMat;

        return (TradeLib.from(sizeToLiq, sizeToLiq.mulCeil(market.rMark) - annualizedIncentive.Int()), liqFeeRate);
    }

    function _getLiqSettings(
        int256 healthRatio
    ) internal view returns (uint256 /*incentiveFactor*/, uint64 /*liqFeeRate*/) {
        LiqSettings memory liqSettings = _ctx().liqSettings;
        uint256 healthRatioUint = uint256(healthRatio); // 0 <= healthRatio < 1
        uint256 k = liqSettings.base + uint256(liqSettings.slope).mulDown(PMath.ONE - healthRatioUint);
        return (PMath.min(k, healthRatioUint), liqSettings.feeRate);
    }

    function _calcDelevTradeAft(
        MarketMem memory market,
        UserMem memory lose,
        int256 sizeToWin,
        int256 loseValue,
        uint256 alpha
    ) internal pure returns (Trade /*delevTrade*/) {
        require(0 <= alpha && alpha <= PMath.ONE && sizeToWin != 0, Err.MarketInvalidDeleverage());

        if (loseValue >= 0) {
            return TradeLib.from(sizeToWin, sizeToWin.mulCeil(market.rMark));
        }

        int256 lossFactor = (int256(alpha) * sizeToWin).rawDivCeil(lose.signedSize);
        int256 loss = loseValue.mulFloor(lossFactor);
        int256 annualizedLoss = (loss * 365 days).rawDivFloor(int256(uint256(market.timeToMat)));

        return TradeLib.from(sizeToWin, sizeToWin.mulCeil(market.rMark) - annualizedLoss);
    }

    function _isReducedOnly(int256 curSize, int256 newTradeSize) internal pure returns (bool) {
        return newTradeSize.abs() <= curSize.abs() && newTradeSize.sign() * curSize.sign() <= 0;
    }
}

// SPDX-License-Identifier: BUSL-1.1
pragma solidity ^0.8.28;

// Libraries
import {Err} from "../../../lib/Errors.sol";
import {PMath} from "../../../lib/math/PMath.sol";
import {TickMath} from "../../../lib/math/TickMath.sol";
import {PaymentLib as Pay} from "../../../lib/PaymentLib.sol";

// Types
import {VMResult, VMResultLib, LongShort, PayFee} from "../../../types/MarketTypes.sol";
import {Side} from "../../../types/Order.sol";
import {Fill} from "../../../types/Trade.sol";

// Core
import {MarketInfoAndState} from "../core/MarketInfoAndState.sol";

// Interfaces
import {IMarketAllEventsAndTypes} from "../../../interfaces/IMarket.sol";

abstract contract MarginViewUtils is IMarketAllEventsAndTypes, MarketInfoAndState {
    using PMath for int256;
    using PMath for uint256;
    using PMath for uint128;
    using PMath for uint32;

    /// @dev Aft suffix means the call must only be post-processing the user
    function _getIMAft(MarketMem memory market, UserMem memory user) internal view returns (VMResult) {
        return VMResultLib.from(_getValueAft(market, user), _calcIM(market, user, _kIM(user.addr)));
    }

    function _getMMAft(MarketMem memory market, UserMem memory user) internal view returns (VMResult) {
        return VMResultLib.from(_getValueAft(market, user), _calcMM(market, user.signedSize, _kMM(user.addr)));
    }

    function _calcIM(MarketMem memory market, UserMem memory user, uint64 kIM) internal pure returns (uint256) {
        uint256 PM = _calcPM(market, user);
        return (PM * kIM * market.timeToMat.max(market.tThresh)).rawDivUp(PMath.ONE_MUL_YEAR);
    }

    /// @dev long, complicated formulas following the white-paper strictly
    function _calcMM(MarketMem memory market, int256 signedSize, uint64 kMM) internal pure returns (uint256) {
        uint256 absSize = signedSize.abs();
        uint256 absMarkRate = market.rMark.abs();

        if (absMarkRate > market.k_iThresh) {
            uint256 scaledTThresh = market.tThresh.mulUp(kMM);
            if (market.timeToMat < scaledTThresh && signedSize * market.rMark > 0) {
                return
                    (absSize * (absMarkRate * market.timeToMat + market.k_iThresh * (scaledTThresh - market.timeToMat)))
                        .rawDivUp(PMath.ONE_MUL_YEAR);
            }
            // else use the calculation outside
        }

        uint256 PM = __calcPMFromRate(absSize, market.rMark, market.k_iThresh);
        return (PM * kMM * market.timeToMat.max(market.tThresh)).rawDivUp(PMath.ONE_MUL_YEAR);
    }

    function _getValueAft(MarketMem memory market, UserMem memory user) internal pure returns (int256) {
        return Pay.calcPositionValue(user.signedSize, market.rMark, market.timeToMat);
    }

    function _calcPM(MarketMem memory market, UserMem memory user) internal pure returns (uint256) {
        int256 S = user.signedSize;
        uint256 pmAlone = __calcPMFromRate(S.abs(), market.rMark, market.k_iThresh);

        (uint256 B_Long, uint256 pmLong) = (user.pmData.sumLongSize, user.pmData.sumLongPM);
        uint256 pmTotalLong;

        if (S < 0 && B_Long <= S.abs()) pmTotalLong = 0;
        else {
            if (S > 0) pmTotalLong = pmLong + pmAlone;
            else pmTotalLong = pmLong > pmAlone ? pmLong - pmAlone : 0;
        }

        (uint256 B_Short, uint256 pmShort) = (user.pmData.sumShortSize, user.pmData.sumShortPM);
        uint256 pmTotalShort;

        if (S > 0 && B_Short <= S.abs()) pmTotalShort = 0;
        else {
            if (S < 0) pmTotalShort = pmShort + pmAlone;
            else pmTotalShort = pmShort > pmAlone ? pmShort - pmAlone : 0;
        }

        return pmTotalLong.max(pmTotalShort);
    }

    function _calcPMFromFill(MarketMem memory market, Fill fill) internal pure returns (uint256) {
        return fill.absCost().max(fill.absSize().mulDown(market.k_iThresh));
    }

    function _calcPMFromTick(
        MarketMem memory market,
        uint256 absSize,
        int16 tickIndex
    ) internal pure returns (uint256) {
        int256 rate = TickMath.getRateAtTick(tickIndex, market.k_tickStep);
        return __calcPMFromRate(absSize, rate, market.k_iThresh);
    }

    function __calcPMFromRate(uint256 absSize, int256 rate, uint256 k_iThresh) private pure returns (uint256) {
        uint256 absRate = rate.abs();
        return absSize.mulDown(absRate.max(k_iThresh));
    }

    // --

    int256 private constant LONG_SIDE = 1;
    int256 private constant SHORT_SIDE = -1;
    int256 private constant ZERO_SIDE = 0;

    /// @dev Rather complicated conditions, also following the white-paper closely but tweak a bit for ease of implementation
    function _checkMargin(
        MarketMem memory market,
        UserMem memory user,
        PayFee post /*postPayment*/,
        LongShort memory orders,
        int256 critHR
    ) internal view returns (bool /*onlyClosing*/, bool /*isStrictIM*/, VMResult /*finalVM*/) {
        int256 rWorst = _getWorstRate(orders, market); // only valid if orders is not empty
        if (!orders.isEmpty()) {
            // users' orders must always be within bounds
            int256 rateBound = _calcRateBound(market, orders.side);
            require(orders.side.checkRateInBound(rWorst, rateBound), Err.MarketOrderRateOutOfBound());
        }

        if (!_isUserClosingOnly(user, orders)) {
            // if user is not closing only, we definitely check isStrictIM
            return (false, true, _getIMAft(market, user));
        }

        // from here on onlyClosing is true
        if (!orders.isEmpty()) {
            if (
                (market.rMark - rWorst) * user.signedSize.sign() >
                int256(mulBase1e4(market.k_iThresh.max(market.rMark.abs()), _ctx().closingOrderBoundBase1e4))
            ) {
                return (true, true, _getIMAft(market, user));
            }
        }

        // change in value and maintenance margin due to the batch must satisfy a condition
        // v_pre - v_aft
        int256 diffValue = Pay.calcPositionValue(user.postSettleSize, market.rMark, market.timeToMat) -
            Pay.calcPositionValue(user.signedSize, market.rMark, market.timeToMat) -
            post.total();

        (uint256 mmPost, int256 diffMargin) = (0, 0);

        {
            // m_pre - m_aft
            uint64 kMM = _kMM(user.addr);
            uint256 mmPre = _calcMM(market, user.postSettleSize, kMM);

            mmPost = _calcMM(market, user.signedSize, kMM);
            diffMargin = mmPre.Int() - mmPost.Int();
        }

        if (diffValue > diffMargin.mulFloor(critHR)) {
            return (true, true, _getIMAft(market, user));
        }

        // Passed all conditions to be exempt from strictIM
        return (true, false, VMResultLib.from(_getValueAft(market, user), mmPost));
    }

    function _isUserClosingOnly(UserMem memory user, LongShort memory orders) private pure returns (bool) {
        int256 preSize = user.postSettleSize;
        int256 finalSize = user.signedSize;

        // size of the position must be reduced (or stays the same)
        if (finalSize.abs() > preSize.abs() || finalSize.sign() * preSize.sign() < 0) {
            return false;
        }

        int256 finalSign = finalSize.sign();

        // total book size for the opposite side of the position must not exceed the position size
        {
            (uint256 longSize, uint256 shortSize) = (user.pmData.sumLongSize, user.pmData.sumShortSize);
            if (finalSign == ZERO_SIDE) {
                if (longSize != 0 || shortSize != 0) return false;
            } else if (finalSign == LONG_SIDE) {
                if (shortSize > finalSize.abs()) return false;
            } else if (finalSign == SHORT_SIDE) {
                if (longSize > finalSize.abs()) return false;
            }
        }

        // no more limit orders are allowed to open more position
        if (!orders.isEmpty()) {
            if (finalSign == ZERO_SIDE) {
                return false;
            } else if (finalSign == LONG_SIDE) {
                if (orders.side == Side.LONG) return false;
            } else if (finalSign == SHORT_SIDE) {
                if (orders.side == Side.SHORT) return false;
            }
        }

        return true;
    }

    function _getWorstRate(LongShort memory orders, MarketMem memory market) internal pure returns (int256) {
        if (orders.isEmpty()) return 0;
        int16 tickWorst = orders.limitTicks[0];
        if (orders.side == Side.LONG) {
            for (uint256 i = 0; i < orders.limitTicks.length; i++) {
                int16 t = orders.limitTicks[i];
                if (t > tickWorst) tickWorst = t;
            }
        } else {
            for (uint256 i = 0; i < orders.limitTicks.length; i++) {
                int16 t = orders.limitTicks[i];
                if (t < tickWorst) tickWorst = t;
            }
        }
        return TickMath.getRateAtTick(tickWorst, market.k_tickStep);
    }

    function _calcRateBound(MarketMem memory market, Side side) internal view returns (int256) {
        int256 rMark = market.rMark;
        if (rMark >= 0) {
            return __calcRateBoundPositive(rMark, market.k_iThresh, side);
        } else {
            return -__calcRateBoundPositive(-rMark, market.k_iThresh, side.opposite());
        }
    }

    function __calcRateBoundPositive(int256 rMark, uint256 k_iThresh, Side side) private view returns (int256) {
        if (rMark >= int256(k_iThresh)) {
            int16 slope = side == Side.LONG ? _ctx().loUpperSlopeBase1e4 : _ctx().loLowerSlopeBase1e4;
            return mulBase1e4(rMark, slope);
        } else {
            int16 constBase1e4 = side == Side.LONG ? _ctx().loUpperConstBase1e4 : _ctx().loLowerConstBase1e4;
            return addBase1e18And1e4(rMark, constBase1e4);
        }
    }

    function mulBase1e4(uint256 x, uint16 y) internal pure returns (uint256) {
        return (x * y) / 1e4;
    }

    function mulBase1e4(int256 x, int16 y) internal pure returns (int256) {
        return (x * y) / 1e4;
    }

    function addBase1e18And1e4(int256 x, int16 y) internal pure returns (int256) {
        return x + int256(y) * 1e14;
    }
}

contracts/core/contracts/core/market/Mar.content:
// SPDX-License-Identifier: BUSL-1.1
pragma solidity ^0.8.28;

// External
import {Proxy} from "@openzeppelin/contracts/proxy/Proxy.sol";

// Interfaces
import {IMarketEntry, IMarketOrderAndOtc, IMarketRiskManagement} from "../../interfaces/IMarket.sol";

// Libraries
import {Err} from "../../lib/Errors.sol";
import {PMath} from "../../lib/math/PMath.sol";

// Types
import {MarketAcc} from "../../types/Account.sol";
import {
    FIndex,
    PayFee,
    LiqResult,
    LongShort,
    TokenId,
    MarketId,
    VMResult,
    GetRequest,
    CancelData
} from "../../types/MarketTypes.sol";
import {OrderId, Side} from "../../types/Order.sol";

// Components
import {MarketInfoAndState} from "./core/MarketInfoAndState.sol";
import {CoreOrderUtils} from "./core/CoreOrderUtils.sol";
import {CoreStateUtils} from "./core/CoreStateUtils.sol";
import {LiquidationViewUtils} from "./margin/LiquidationViewUtils.sol";

contract MarketEntry is IMarketEntry, CoreOrderUtils, CoreStateUtils, LiquidationViewUtils, Proxy {
    using PMath for uint256;

    uint256 public constant VERSION = 2;

    address internal immutable _MARKET_SETTING_AND_VIEW;
    address internal immutable _MARKET_ORDER_AND_OTC;
    address internal immutable _MARKET_RISK_MANAGEMENT;

    constructor(
        address marketHub_,
        address marketSetAndView_,
        address marketOrderAndOtc_,
        address marketRiskManagement_
    ) MarketInfoAndState(marketHub_) {
        _disableInitializers();
        _MARKET_SETTING_AND_VIEW = marketSetAndView_;
        _MARKET_ORDER_AND_OTC = marketOrderAndOtc_;
        _MARKET_RISK_MANAGEMENT = marketRiskManagement_;
    }

    function _implementation() internal view override returns (address) {
        if (msg.sig == IMarketOrderAndOtc.orderAndOtc.selector) {
            return _MARKET_ORDER_AND_OTC;
        }
        if (
            msg.sig == IMarketRiskManagement.forceDeleverage.selector ||
            msg.sig == IMarketRiskManagement.forcePurgeOobOrders.selector
        ) {
            return _MARKET_RISK_MANAGEMENT;
        }
        return _MARKET_SETTING_AND_VIEW;
    }

    function settleAndGet(
        MarketAcc userAddr,
        GetRequest getType
    ) external onlyMarketHub returns (VMResult /*res*/, PayFee /*settle*/, int256 /*signedSize*/, uint256 /*nOrders*/) {
        MarketMem memory market = _readMarket({checkPause: NO, checkMaturity: NO});
        (VMResult res, PayFee settle, int256 signedSize, uint256 nOrders) = _shortcutSettleAndGet(
            userAddr,
            market,
            getType
        );
        _writeMarketSkipOICheck(market);
        return (res, settle, signedSize, nOrders);
    }

    function cancel(
        MarketAcc userAddr,
        CancelData memory cancelData,
        bool isForceCancel
    ) external onlyMarketHub returns (PayFee /*settle*/, OrderId[] memory /*removedIds*/) {
        MarketMem memory market = _readMarket({checkPause: isForceCancel ? NO : YES, checkMaturity: YES});
        (UserMem memory user, PayFee settle) = _initUser(userAddr, market);

        OrderId[] memory removedIds = _coreRemoveAft(market, user, cancelData, isForceCancel);

        if (isForceCancel) {
            _incDelevLiqNonce(userAddr);
        }

        _writeUserNoCheck(user, market);
        _writeMarketSkipOICheck(market);

        return (settle, removedIds);
    }

    function liquidate(
        MarketAcc liqAddr,
        MarketAcc vioAddr,
        int256 sizeToLiq,
        int256 vioHealthRatio,
        int256 critHR
    ) external onlyMarketHub returns (LiqResult memory res) {
        require(liqAddr != vioAddr, Err.MarketInvalidLiquidation());

        MarketMem memory market = _readMarket({checkPause: YES, checkMaturity: YES});
        (UserMem memory liq, PayFee liqSettle) = _initUser(liqAddr, market);
        (UserMem memory vio, PayFee vioSettle) = _initUser(vioAddr, market);

        res.liqSettle = liqSettle;
        res.vioSettle = vioSettle;

        require(_isReducedOnly(vio.signedSize, -sizeToLiq), Err.MarketLiqNotReduceSize());

        _coreRemoveAllAft(market, vio, true);

        uint64 liqFeeRate;
        (res.liqTrade, liqFeeRate) = _calcLiqTradeAft(market, vio, sizeToLiq, vioHealthRatio);
        (res.liqPayment, res.vioPayment) = _mergeOTCAft(liq, vio, market, res.liqTrade, 0, liqFeeRate);

        _incDelevLiqNonce(vioAddr);

        LongShort memory empty;

        (res.isStrictIMLiq, res.finalVMLiq) = _writeUser(liq, market, res.liqPayment, empty, critHR, CLOCheck.SKIP);
        _writeUserNoCheck(vio, market);
        _writeMarketSkipOICheck(market);

        emit Liquidate(liqAddr, vioAddr, res.liqTrade, res.liqPayment.fee());

        return res;
    }

    function getMarkRate() external returns (int256) {
        return _getMarkRate();
    }

    function getImpliedRate()
        external
        view
        returns (
            int128 /*lastTradedRate*/,
            int128 /*oracleRate*/,
            uint32 /*lastTradedTime*/,
            uint32 /*observationWindow*/
        )
    {
        uint8 tickStep = _ctx().k_tickStep;
        return _ctx().impliedRate.getCurrentRate(tickStep);
    }

    function getBestFeeRates(
        MarketAcc user,
        MarketAcc otcCounter
    ) external view returns (uint64 /*takerFee*/, uint64 /*otcFee*/) {
        return (_getTakerFeeRate(user).Uint64(), _getOtcFeeRate(user, otcCounter).Uint64());
    }

    function getNextNTicks(
        Side side,
        int16 startTick,
        uint256 maxNTicks
    ) external view returns (int16[] memory /*ticks*/, uint256[] memory /*tickSizes*/) {
        return _getNextNTicks(side, startTick, maxNTicks);
    }

    function descriptor()
        external
        view
        returns (
            bool /*isIsolatedOnly*/,
            TokenId /*tokenId*/,
            MarketId /*marketId*/,
            uint32 /*maturity*/,
            uint8 /*tickStep*/,
            uint16 /*iTickThresh*/,
            uint32 /*latestFTime*/
        )
    {
        return (
            _ctx().k_isIsolatedOnly,
            _ctx().k_tokenId,
            _ctx().k_marketId,
            _ctx().k_maturity,
            _ctx().k_tickStep,
            _ctx().k_iTickThresh,
            _ctx().latestFTime
        );
    }

    function getLatestFIndex() external view returns (FIndex) {
        return _toFIndex(_ctx().latestFTag);
    }

    function getLatestFTime() external view returns (uint32) {
        return _ctx().latestFTime;
    }

    function getDelevLiqNonce(MarketAcc user) external view returns (uint24) {
        return _accState(user).delevLiqNonce;
    }

    // slither-disable-next-line locked-ether
    receive() external payable {
        revert();
    }
}

contracts/core/contracts/core/market/ord.content:
// SPDX-License-Identifier: BUSL-1.1
pragma solidity ^0.8.28;

// Generated
import {GeneratedStorageSlots} from "../../../generated/slots.sol";

// Interfaces
import {IMarketAllEventsAndTypes} from "../../../interfaces/IMarket.sol";

// Libraries
import {LowLevelArrayLib} from "../../../lib/ArrayLib.sol";
import {PMath} from "../../../lib/math/PMath.sol";
import {TickMath} from "../../../lib/math/TickMath.sol";

// Types
import {AccountLib, MarketAcc} from "../../../types/Account.sol";
import {LongShort, SweptF, FTag} from "../../../types/MarketTypes.sol";
import {OrderId, OrderIdLib, OrderStatus, Side} from "../../../types/Order.sol";
import {Trade, TradeLib, Fill, FillLib} from "../../../types/Trade.sol";

// Components
import {Tick, TickMatchResult} from "./Tick.sol";
import {TickBitmap} from "./TickBitmap.sol";

abstract contract OrderBookUtils is IMarketAllEventsAndTypes {
    using PMath for uint256;
    using LowLevelArrayLib for OrderId[];
    using LowLevelArrayLib for uint256[];
    using LowLevelArrayLib for int16[];

    struct OrderBook {
        TickBitmap tickBitmap;
        mapping(int16 => Tick) ticks;
    }

    struct OrderBookStorageStruct {
        OrderBook bookLong;
        OrderBook bookShort;
        mapping(MarketAcc => uint40) makerToNonce;
        mapping(uint40 => MarketAcc) nonceToMaker;
        uint40 countMaker;
        // empty for upgradability
    }

    function _OS() internal pure returns (OrderBookStorageStruct storage $) {
        bytes32 slot = GeneratedStorageSlots.ORDERBOOK_STORAGE_LOCATION;
        assembly {
            $.slot := slot
        }
    }

    function _bookAdd(MarketAcc maker, LongShort memory orders, OrderId[] memory orderIds, uint256 appendPos) internal {
        OrderBook storage self = _getBook(orders.side);
        uint40 makerNonce = __getOrCreateMakerNonce(maker);

        for (uint256 i = 0; i < orders.sizes.length; i++) {
            uint128 curSize128 = orders.sizes[i].Uint128();
            int16 tickIndex = orders.limitTicks[i];

            (uint40 orderIndex, uint256 oldTickSum) = self.ticks[tickIndex].insertOrder(curSize128, makerNonce);

            if (oldTickSum == 0) {
                self.tickBitmap.set(tickIndex);
            }

            unchecked {
                orderIds[appendPos + i] = OrderIdLib.from(orders.side, tickIndex, orderIndex);
            }
        }

        (OrderId[] memory addedIds, bytes32 borrow) = LowLevelArrayLib.sliceFromTemp(orderIds, appendPos);
        emit LimitOrderPlaced(maker, addedIds, orders.sizes);
        LowLevelArrayLib.restoreSlice(addedIds, borrow);
    }

    function _bookRemove(
        OrderId[] memory ids,
        bool isStrict,
        bool isForced
    ) internal returns (uint256[] memory removedSizes) {
        uint256 len = ids.length;
        if (len == 0) return removedSizes;

        uint256 removedCnt = 0;
        removedSizes = new uint256[](len);
        for (uint256 i = 0; i < len; ++i) {
            (Side side, int16 tickIndex, uint40 orderIndex) = ids[i].unpack();

            OrderBook storage self = _getBook(side);
            Tick storage tick = self.ticks[tickIndex];
            (uint256 removedSize, uint256 newTickSum) = tick.tryRemove(orderIndex, isStrict);
            if (removedSize > 0) {
                if (newTickSum == 0) {
                    self.tickBitmap.reset(tickIndex);
                }

                ids[removedCnt] = ids[i];
                removedSizes[removedCnt] = removedSize;
                removedCnt = removedCnt.inc();
            }
        }

        ids.setShorterLength(removedCnt);
        removedSizes.setShorterLength(removedCnt);

        if (removedCnt > 0) {
            if (isForced) {
                emit LimitOrderForcedCancelled(ids);
            } else {
                emit LimitOrderCancelled(ids);
            }
        }
    }

    function _bookCanSettleSkipSizeCheck(OrderId id) internal view returns (bool) {
        (Side side, int16 tickIndex, uint40 orderIndex) = id.unpack();
        Tick storage tick = _getBook(side).ticks[tickIndex];
        return tick.canSettleSkipSizeCheck(orderIndex);
    }

    /// @dev Pre-condition: the order is SETTLED.
    /// @dev `sweptF.fTag` will be retrieved from tick when the passed in `fTag == FTagLib.ZERO`.
    /// @dev `sweptF.fTag` will be `fTag` when the passed in `fTag != FTagLib.ZERO`.
    function _bookGetSettleInfo(OrderId id, uint8 tickStep, FTag fTag) internal view returns (SweptF memory sweptF) {
        (Side side, int16 tickIndex, uint40 orderIndex) = id.unpack();
        Tick storage tick = _getBook(side).ticks[tickIndex];

        uint256 settledSize = 0;
        if (fTag.isZero()) {
            (settledSize, fTag) = tick.getSettleSizeAndFTag(orderIndex);
        } else {
            settledSize = tick.getSettleSize(orderIndex);
        }

        sweptF.assign(fTag, FillLib.from3(side, settledSize, TickMath.getRateAtTick(tickIndex, tickStep)));
    }

    struct MatchAux {
        Side side;
        uint256[] sizes;
        int16[] limitTicks;
        uint8 tickStep;
        FTag latestFTag;
    }

    /// @dev sizes will become the remaining (unmatched) sizes after this function.
    /// @dev For each index i, if sizes[i] is **FULLY** matched (become zero), sizes[i] and limitTicks[i] will be removed.
    function _bookMatch(
        uint8 _tickStep,
        FTag _latestFTag,
        LongShort memory orders
    )
        internal
        returns (
            Trade totalMatched,
            Fill partialFill,
            MarketAcc partialMaker,
            int16 lastMatchedTick,
            int256 lastMatchedRate
        )
    {
        MatchAux memory $ = MatchAux({
            side: orders.side.opposite(),
            sizes: orders.sizes,
            limitTicks: orders.limitTicks,
            tickStep: _tickStep,
            latestFTag: _latestFTag
        });

        if (orders.tif.shouldSkipMatchableOrders()) {
            _removeMatchableOrders($);
            return (TradeLib.ZERO, FillLib.ZERO, AccountLib.ZERO_MARKET_ACC, 0, 0);
        }

        OrderBook storage self = _getBook($.side);
        TickMatchResult memory result;

        uint256 curOrder = 0;
        while (true) {
            (int16 curTick, bool found) = self.tickBitmap.begin($.side);
            if (!found) break;

            curOrder = __nextMatchableOrder($.side, curTick, $.limitTicks, curOrder);
            if (curOrder == $.sizes.length) break;

            uint256 matched;
            (matched, curOrder) = _processTickMatches(self, $, curOrder, curTick, result);

            lastMatchedTick = curTick;
            lastMatchedRate = TickMath.getRateAtTick(curTick, $.tickStep);
            totalMatched = totalMatched + TradeLib.from3($.side, matched, lastMatchedRate);

            if (result.beginFullyFilledOrderIndex != result.endFullyFilledOrderIndex) {
                OrderId from = OrderIdLib.from($.side, curTick, result.beginFullyFilledOrderIndex);
                OrderId to = OrderIdLib.from($.side, curTick, result.endFullyFilledOrderIndex - 1);
                emit LimitOrderFilled(from, to);
            }

            if (result.partialSize > 0) {
                // assert($.sizes[curOrder] == 0); // can be proven to be true

                partialMaker = _OS().nonceToMaker[result.partialMakerNonce];
                partialFill = FillLib.from3($.side, result.partialSize, lastMatchedRate);

                OrderId id = OrderIdLib.from($.side, curTick, result.endFullyFilledOrderIndex);
                emit LimitOrderPartiallyFilled(id, result.partialSize);
                break;
            }

            if ($.sizes[curOrder] == 0) {
                break;
            }
        }

        __removeZeroSizes($.sizes, $.limitTicks);
        totalMatched = totalMatched.opposite();
    }

    function _removeMatchableOrders(MatchAux memory $) private view {
        OrderBook storage self = _getBook($.side);
        (int16 bestTick, bool found) = self.tickBitmap.begin($.side);
        if (!found) return;

        for (uint256 i = 0; i < $.sizes.length; ++i) {
            if ($.side.canMatch($.limitTicks[i], bestTick)) {
                $.sizes[i] = 0;
            }
        }
        __removeZeroSizes($.sizes, $.limitTicks);
    }

    /// @dev Process all matches at current tick level, including accumulation and matching
    function _processTickMatches(
        OrderBook storage self,
        MatchAux memory $,
        uint256 startOrder,
        int16 curTick,
        TickMatchResult memory result
    ) private returns (uint256 matched, uint256 curOrder) {
        Tick storage tick = self.ticks[curTick];
        uint256 curTickSum = tick.getTickSum();

        curOrder = startOrder;
        // First accumulate any fully matchable orders
        while ($.sizes[curOrder] <= curTickSum) {
            uint256 nxtOrder = __nextMatchableOrder($.side, curTick, $.limitTicks, curOrder.inc());
            if (nxtOrder == $.sizes.length) break;

            $.sizes[nxtOrder] += $.sizes[curOrder];
            $.sizes[curOrder] = 0;
            curOrder = nxtOrder;
        }

        // Then process the final match (either full or partial)
        if (curTickSum <= $.sizes[curOrder]) {
            matched = curTickSum;
            tick.matchAllFillResult($.latestFTag, result);
            self.tickBitmap.reset(curTick);
        } else {
            matched = $.sizes[curOrder];
            tick.matchPartialFillResult(matched.Uint128(), $.latestFTag, result);
        }

        $.sizes[curOrder] -= matched;
    }

    /// @dev only called by forcePurgeOobOrders
    function _bookPurgeOob(
        uint8 tickStep,
        int256 boundRate,
        FTag purgeTag,
        Side side,
        uint256 maxNTicksToPurge
    ) internal returns (uint256 /*nTicksPurged*/) {
        // assert(purgeTag.isPurge());

        OrderBook storage self = _getBook(side);
        TickMatchResult memory result;

        uint256 nTicksPurged = 0;
        for (; nTicksPurged < maxNTicksToPurge; nTicksPurged++) {
            (int16 curTick, bool found) = self.tickBitmap.begin(side);
            if (!found) {
                break;
            }

            int256 tickRate = TickMath.getRateAtTick(curTick, tickStep);
            if (side.checkRateInBound(tickRate, boundRate)) break;

            self.ticks[curTick].matchAllFillResult(purgeTag, result);
            self.tickBitmap.reset(curTick);

            OrderId from = OrderIdLib.from(side, curTick, result.beginFullyFilledOrderIndex);
            OrderId to = OrderIdLib.from(side, curTick, result.endFullyFilledOrderIndex - 1);

            emit OobOrdersPurged(from, to);
        }

        return nTicksPurged;
    }

    function __nextMatchableOrder(
        Side side,
        int16 curTick,
        int16[] memory limitTicks,
        uint256 curOrder
    ) private pure returns (uint256) {
        uint256 n = limitTicks.length;
        while (curOrder < n && !side.canMatch(limitTicks[curOrder], curTick)) curOrder = curOrder.inc();
        return curOrder;
    }

    function __removeZeroSizes(uint256[] memory sizes, int16[] memory limitTicks) private pure {
        uint256 keepCnt = 0;
        for (uint256 i = 0; i < sizes.length; i++) {
            if (sizes[i] == 0) continue;
            (sizes[keepCnt], limitTicks[keepCnt]) = (sizes[i], limitTicks[i]);
            keepCnt = keepCnt.inc();
        }
        sizes.setShorterLength(keepCnt);
        limitTicks.setShorterLength(keepCnt);
    }

    function _getNextNTicks(
        Side side,
        int16 startTick,
        uint256 nTicks
    ) internal view returns (int16[] memory ticks, uint256[] memory sizes) {
        unchecked {
            if (nTicks == 0) return (ticks, sizes);
            OrderBook storage self = _getBook(side);

            uint256 nFound;
            bool found;

            if (startTick == side.tickToGetFirstAvail()) {
                (startTick, found) = self.tickBitmap.begin(side);
                if (!found) return (ticks, sizes);

                ticks = new int16[](nTicks);
                ticks[0] = startTick;
                nFound = 1;
            } else {
                ticks = new int16[](nTicks);
            }

            for (int16 iTick = startTick; nFound < nTicks; ) {
                (iTick, found) = self.tickBitmap.next(iTick, side);
                if (!found) break;
                ticks[nFound++] = iTick;
            }

            ticks.setShorterLength(nFound);

            sizes = new uint256[](nFound);
            for (uint256 i = 0; i < nFound; i++) {
                sizes[i] = self.ticks[ticks[i]].getTickSum();
            }
        }
    }

    function _getBook(Side side) internal view returns (OrderBook storage) {
        return side == Side.LONG ? _OS().bookLong : _OS().bookShort;
    }

    function __getOrCreateMakerNonce(MarketAcc maker) private returns (uint40 /*makerNonce*/) {
        uint40 makerNonce = _OS().makerToNonce[maker];
        if (makerNonce == 0) {
            makerNonce = _OS().countMaker + 1;
            _OS().countMaker = makerNonce;
            _OS().makerToNonce[maker] = makerNonce;
            _OS().nonceToMaker[makerNonce] = maker;
        }

        return makerNonce;
    }

    // ------------ Only used in OffView ------------

    function _getOrderStatus(OrderId id) internal view returns (OrderStatus status) {
        (Side side, int16 tickIndex, uint40 orderIndex) = id.unpack();
        Tick storage tick = _getBook(side).ticks[tickIndex];
        (status, ) = tick.getOrderStatusAndSize(orderIndex);
    }
}

