        (int128 markRate, bool needUpdateCache) = _getMarkRateInternal();
        if (needUpdateCache) _writeCacheMarkRate(markRate);
        return markRate;
    }

    function _getMarkRateView() internal view returns (int256 markRate) {
        (markRate, ) = _getMarkRateInternal();
    }

